CREATE OR REPLACE PROCEDURE p_job_create_bond_info_all()
LANGUAGE plpgsql
AS $$
DECLARE
    colname TEXT;
    sql TEXT;
BEGIN
    TRUNCATE TABLE tmp_bond_info_all_20010;
    INSERT INTO tmp_bond_info_all_20010(f_val, def_id, id)
    SELECT field_value, FIELD_DEFINITION_ID, t2.ID
    FROM T_OBJECT_FIELD_DATA t1, T_PJ_Bond_Info t2
    WHERE t1.OBJECT_NO = 20010
      AND t1.FIELD_VALUE IS NOT NULL
      AND t1.parent_id = t2.APPLY_ID;

    TRUNCATE TABLE tmp_bond_info_all_20020;
    INSERT INTO tmp_bond_info_all_20020(f_val, def_id, id)
    SELECT field_value, FIELD_DEFINITION_ID, t2.id AS bondId
    FROM T_OBJECT_FIELD_DATA t1, T_PJ_Bond_Info t2
    WHERE t1.OBJECT_NO = 20020
      AND t1.FIELD_VALUE IS NOT NULL
      AND t1.PARENT_ID = t2.TEMP_BONDID;

    TRUNCATE TABLE t_pj_bond_info_all;
    INSERT INTO t_pj_bond_info_all(id, temp_bondid, apply_id)
    SELECT t1.ID, t1.TEMP_BONDID, t1.APPLY_ID
    FROM T_PJ_Bond_Info t1
    WHERE 1=1;

    FOR colname IN
        SELECT column_name
        FROM information_schema.columns
        WHERE table_name = 't_pj_bond_info_all'
          AND column_name LIKE 'def%'
    LOOP
        sql := 'UPDATE t_pj_bond_info_all a SET ' || colname || ' = b.f_val FROM tmp_bond_info_all_20020 b WHERE a.id = b.id AND b.def_id = ' || replace(colname, 'def_', '');
        EXECUTE sql;

        sql := 'UPDATE t_pj_bond_info_all a SET ' || colname || ' = b.f_val FROM tmp_bond_info_all_20010 b WHERE a.id = b.id AND a.' || colname || ' IS NULL AND b.def_id = ' || replace(colname, 'def_', '');
        EXECUTE sql;
    END LOOP;
END;
$$;

CREATE OR REPLACE FUNCTION bulk_delete_by_ids(p_id_list VARCHAR) RETURNS void AS $$
DECLARE
    v_sql VARCHAR(1000);
BEGIN
    v_sql := 'DELETE FROM logs WHERE log_id IN (' || p_id_list || ')';
    EXECUTE v_sql;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION archive_old_records(p_archive_date DATE) RETURNS void AS $$
DECLARE
    v_deleted_rows INTEGER;
BEGIN
    WITH deleted AS (
        DELETE FROM active_data
        WHERE record_date < p_archive_date
        RETURNING record_id, record_data
    )
    INSERT INTO archive_table (record_id, record_data)
    SELECT record_id, record_data FROM deleted;
    GET DIAGNOSTICS v_deleted_rows = ROW_COUNT;
    INSERT INTO audit_log (log_message) VALUES (v_deleted_rows || ' rows archived.');
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION GETEMPLOYEESTATS(p_dept_id NUMERIC, OUT p_result TEXT) AS $$
DECLARE
    v_total_emp INTEGER;
    v_avg_salary NUMERIC;
    v_max_salary NUMERIC;
    v_active_projects INTEGER;
    v_result RECORD;
    v_cursor REFCURSOR;
    v_sql TEXT;
    v_dept_name VARCHAR(50);
BEGIN
    SELECT department_name INTO v_dept_name FROM DEPARTMENTS WHERE department_id = p_dept_id;
    SELECT COUNT(*), AVG(salary), MAX(salary) INTO v_total_emp, v_avg_salary, v_max_salary
    FROM EMPLOYEES WHERE department_id = p_dept_id;
    SELECT COUNT(*) INTO v_active_projects FROM PROJECTS WHERE department_id = p_dept_id AND status = 'ACTIVE';
    v_sql := 'SELECT employee_id, last_name, salary FROM employees WHERE department_id = $1 ORDER BY salary DESC LIMIT 5';
    OPEN v_cursor FOR EXECUTE v_sql USING p_dept_id;
    p_result := '{  "department": "' || v_dept_name || '",  "total_employees": ' || v_total_emp || ',  "salary_stats": {    "average": ' || v_avg_salary || ',    "max": ' || v_max_salary || '  },  "active_projects": ' || v_active_projects || ',  "top_earners": [';
    LOOP
        FETCH v_cursor INTO v_result;
        EXIT WHEN NOT FOUND;
        p_result := p_result || '    {"id": ' || v_result.employee_id || ', "name": "' || v_result.last_name || '", "salary": ' || v_result.salary || '},';
    END LOOP;
    p_result := RTRIM(p_result, ',') || '  ]}';
    CLOSE v_cursor;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        p_result := '{"error": "Department not found"}';
    WHEN OTHERS THEN
        p_result := '{"error": "' || SQLERRM || '"}';
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE PROCEDURE usp_UpdateOrderStatus(
    p_CustomerID INT,
    p_OldStatus VARCHAR(20),
    p_NewStatus VARCHAR(20),
    OUT p_RowsUpdated INT,
    OUT p_ErrorMessage VARCHAR(200),
    OUT p_Status INT
)
LANGUAGE plpgsql
AS $$
DECLARE
    OrderCount INT;
    ProcessingFee DECIMAL(10,2) := 0;
    fee_cursor CURSOR FOR
        SELECT Fee
        FROM OrderDetails
        WHERE OrderID IN (
            SELECT OrderID
            FROM Orders
            WHERE CustomerID = p_CustomerID
              AND Status = p_NewStatus
        );
BEGIN
    IF p_OldStatus = p_NewStatus THEN
        p_ErrorMessage := '新旧状态不能相同';
        p_Status := 400;
        RETURN;
    END IF;

    UPDATE Orders
    SET Status = p_NewStatus,
        LastUpdated = CURRENT_TIMESTAMP
    WHERE CustomerID = p_CustomerID
      AND Status = p_OldStatus
      AND OrderDate > (CURRENT_TIMESTAMP - INTERVAL '3 months');

    GET DIAGNOSTICS p_RowsUpdated = ROW_COUNT;

    IF p_RowsUpdated = 0 THEN
        p_ErrorMessage := '未找到符合条件的订单';
        p_Status := 404;
        RETURN;
    END IF;

    INSERT INTO OrderLog (OrderID, OldStatus, NewStatus, ChangeDate)
    SELECT OrderID,
           p_OldStatus,
           p_NewStatus,
           CURRENT_TIMESTAMP
    FROM Orders
    WHERE CustomerID = p_CustomerID
      AND Status = p_NewStatus;

    ProcessingFee := 0;
    OPEN fee_cursor;
    FETCH NEXT FROM fee_cursor INTO ProcessingFee;
    WHILE FOUND LOOP
        ProcessingFee := ProcessingFee * 0.95;
        FETCH NEXT FROM fee_cursor INTO ProcessingFee;
    END LOOP;
    CLOSE fee_cursor;

    p_ErrorMessage := '更新成功';
    p_Status := 200;
    RETURN;

EXCEPTION
    WHEN OTHERS THEN
        p_ErrorMessage := SQLERRM;
        p_Status := 500;
        RETURN;
END;
$$;

CREATE FUNCTION sp_GetCustomerOrders (customer_id NCHAR(5))
RETURNS SETOF Orders
AS
$$
BEGIN
    RETURN QUERY SELECT * FROM Orders WHERE CustomerID = customer_id;
END;
$$
LANGUAGE plpgsql;

